// Génère une image Story 1080×1920 pour partage Instagram/Stories
async function generateShareStory(type, id) {
  const idNum = typeof id === 'string' ? parseInt(id, 10) : id;
  let item = null;
  let title = "Découvrez sur MapEvent !";
  if (type === "event") {
    item = eventsData.find(e => e.id === idNum);
    if (item) title = item.title || item.name || title;
  } else if (type === "booking") {
    item = bookingsData.find(b => b.id === idNum);
    if (item) title = item.title || item.name || title;
  } else if (type === "service") {
    item = servicesData.find(s => s.id === idNum);
    if (item) title = item.title || item.name || title;
  }
  const url = `${window.location.origin}${window.location.pathname}?${type}=${idNum}`;
  const W = 1080, H = 1920;
  const canvas = document.createElement('canvas');
  canvas.width = W;
  canvas.height = H;
  const ctx = canvas.getContext('2d');
  
  // Fond gradient
  const grad = ctx.createLinearGradient(0, 0, W, H);
  grad.addColorStop(0, '#0f172a');
  grad.addColorStop(0.5, '#1e293b');
  grad.addColorStop(1, '#020617');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, W, H);
  
  // Image de l'item (si disponible)
  let imgUrl = item && typeof getImageCandidatesForItem === 'function' 
    ? (getImageCandidatesForItem(item)[0] || '') 
    : '';
  if (imgUrl && !imgUrl.startsWith('http')) {
    imgUrl = (imgUrl.startsWith('/') ? window.location.origin : '') + imgUrl;
  }
  if (imgUrl) {
    try {
      const img = await new Promise((resolve, reject) => {
        const i = new Image();
        i.crossOrigin = 'anonymous';
        i.onload = () => resolve(i);
        i.onerror = reject;
        i.src = imgUrl;
      });
      const maxH = H * 0.45;
      const ratio = img.naturalWidth / img.naturalHeight;
      const drawH = Math.min(maxH, img.naturalHeight);
      const drawW = ratio * drawH;
      const sx = (W - drawW) / 2;
      ctx.drawImage(img, 0, 0, img.naturalWidth, img.naturalHeight, sx, 0, drawW, drawH);
    } catch (_) {}
  }
  
  // Overlay sombre
  ctx.fillStyle = 'rgba(0,0,0,0.4)';
  ctx.fillRect(0, 0, W, H);
  
  // Zone contenu
  const pad = 60;
  ctx.fillStyle = '#ffffff';
  ctx.font = 'bold 52px system-ui, sans-serif';
  ctx.textAlign = 'center';
  const lines = (title || '').match(/.{1,28}/g) || [''];
  lines.slice(0, 3).forEach((line, i) => {
    ctx.fillText(line, W / 2, H * 0.5 + i * 60, W - pad * 2);
  });
  
  // Date/lieu
  if (item) {
    ctx.fillStyle = '#94a3b8';
    ctx.font = 'bold 32px system-ui, sans-serif';
    let sub = '';
    if (item.startDate) sub = new Date(item.startDate).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' });
    if (item.city || item.address) sub += (sub ? ' \u2022 ' : '') + (item.city || item.address || '').substring(0, 40);
    if (sub) ctx.fillText(sub, W / 2, H * 0.62, W - pad * 2);
  }
  
  // QR code (API publique)
  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(url)}`;
  try {
    const qrImg = await new Promise((resolve, reject) => {
      const i = new Image();
      i.crossOrigin = 'anonymous';
      i.onload = () => resolve(i);
      i.onerror = reject;
      i.src = qrUrl;
    });
    ctx.fillStyle = '#fff';
    ctx.fillRect((W - 240) / 2, H - 320, 240, 240);
    ctx.drawImage(qrImg, (W - 200) / 2, H - 310, 200, 200);
  } catch (_) {}
  
  // Branding MapEvent
  ctx.fillStyle = '#00ffc3';
  ctx.font = 'bold 36px system-ui, sans-serif';
  ctx.fillText('MapEvent', W / 2, H - 50);
  
  // Télécharger ou partager
  canvas.toBlob(blob => {
    const u = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = u;
    a.download = `mapevent-story-${type}-${idNum}.png`;
    a.click();
    URL.revokeObjectURL(u);
    if (typeof showNotification === 'function') showNotification('📱 Image Story téléchargée ! Partagez-la dans vos Stories.', 'success');
  }, 'image/png');
}
window.generateShareStory = generateShareStory;

function closeShareModal(event) {
  if (event && event.target !== event.currentTarget) return;
  const modal = document.getElementById('share-modal');
  if (modal) modal.remove();
}

function copyShareLink(url) {
  navigator.clipboard.writeText(url).then(() => {
    showNotification("🔗 Lien copié dans le presse-papier !", "success");
    closeShareModal();
  }).catch(() => {
    // Fallback pour les navigateurs qui ne supportent pas clipboard
    const input = document.querySelector('#share-modal input');
    if (input) {
      input.select();
      document.execCommand('copy');
      showNotification("🔗 Lien copié !", "success");
      closeShareModal();
    }
  });
}

// Exposer les fonctions
window.closeShareModal = closeShareModal;
window.copyShareLink = copyShareLink;
window.shareItem = shareItem;
// Mettre à jour la fonction globale avec l'implémentation complète
// sharePopup appelle directement shareItem maintenant que shareItem est défini
// Cette assignation remplace le stub défini plus tôt
window.sharePopup = function(type, id) {
  if (typeof shareItem === 'function') {
    shareItem(type, id);
  } else {
    console.warn('sharePopup: shareItem not available');
  }
};

// ============================================
// NOTIFICATIONS
// ============================================
function localizeNotificationMessage(message) {
  if (!message || typeof window.t !== 'function') return message;
  const text = String(message);
  const match = text.match(/^\s*([^A-Za-z0-9À-ÿ]*?)\s*(.*)$/);
  const lead = match ? match[1] : "";
  const core = (match ? match[2] : text).trim();
  const keyByCore = {
    "Erreur lors de la connexion Google": "notif_google_login_error",
    "Connexion expirée. Réessayez en cliquant sur Connexion Google.": "notif_login_expired_retry_google",
    "Impossible d’échanger le code (token).": "notif_token_exchange_failed",
    "Impossible d'echanger le code (token).": "notif_token_exchange_failed",
    "Compte créé avec succès ! Vous êtes maintenant connecté.": "notif_account_created_connected",
    "Veuillez compléter votre profil pour continuer.": "notif_complete_profile_continue",
    "Connexion Google réussie !": "notif_google_login_success",
    "Connecté (token reçu).": "notif_connected_token_received",
    "L'artiste n'est plus visible sur la carte. Rapprochez-vous de sa position.": "notif_artist_not_visible",
    "Lecture directe bloquée, ouverture du lien audio.": "notif_direct_play_blocked_open_link",
    "Erreur de lecture audio, ouverture du lien source.": "notif_audio_error_open_source",
    "Item introuvable": "notif_item_not_found",
    "Filtres réinitialisés - Tous les points affichés": "notif_filters_reset_all_points",
    "Veuillez vous connecter pour publier": "notif_login_required_publish",
    "Liens collés": "notif_links_pasted",
    "Accès presse-papiers refusé": "notif_clipboard_access_denied",
    "Formulaire réinitialisé": "notif_form_reset",
    "Aucun code promo à copier": "notif_no_promo_code_to_copy",
    "Code promo copié": "notif_promo_code_copied",
    "Code sélectionné: Ctrl+C": "notif_promo_code_selected_ctrl_c",
    "Like ajouté": "notif_like_added",
    "Like retiré": "notif_like_removed",
    "Ajouté aux favoris": "notif_favorite_added",
    "Retiré des favoris": "notif_favorite_removed",
    "Participation annulée": "notif_participation_cancelled",
    "Ajouté à votre agenda.": "notif_added_to_agenda",
    "Retiré de l'agenda": "notif_removed_from_agenda",
    "Itinéraire ouvert dans Google Maps": "notif_route_opened_google_maps",
    "Lien copié dans le presse-papier !": "notif_link_copied_clipboard"
  };
  const key = keyByCore[core];
  if (!key) return message;
  const translated = window.t(key) || core;
  return (lead ? (lead + " ") : "") + translated;
}

function showNotification(message, type = "info", options = {}) {
  message = localizeNotificationMessage(message);
  const existing = document.getElementById("notification-toast");
  if (existing) existing.remove();

  const colors = {
    success: "#22c55e",
    error: "#ef4444",
    info: "#3b82f6",
    warning: "#f59e0b"
  };

  const duration = options.duration || 3000;
  const actionLabel = options.actionLabel || null;
  const onAction = options.onAction || null;
  const autoClose = options.autoClose !== false;

  const toast = document.createElement("div");
  toast.id = "notification-toast";
  
  // Construire le contenu avec action si fournie
  let content = `<div style="display:flex;align-items:center;gap:12px;">`;
  content += `<span style="flex:1;">${message}</span>`;
  if (actionLabel && onAction) {
    const actionId = `toast-action-${Date.now()}`;
    content += `<button id="${actionId}" style="background:rgba(255,255,255,0.2);border:none;color:white;padding:6px 12px;border-radius:6px;cursor:pointer;font-weight:600;font-size:13px;white-space:nowrap;transition:background 0.2s;">${actionLabel}</button>`;
    setTimeout(() => {
      const btn = document.getElementById(actionId);
      if (btn) {
        btn.addEventListener('click', (e) => {
          e.stopPropagation();
          onAction();
          toast.remove();
        });
        btn.style.pointerEvents = 'auto';
      }
    }, 10);
  }
  content += `</div>`;
  
  toast.innerHTML = content;
  toast.style.cssText = `
    position: fixed;
    bottom: 20px;
    left: 50%;
    transform: translateX(-50%);
    background: ${colors[type] || colors.info};
    color: white;
    padding: 12px 24px;
    border-radius: 12px;
    font-size: 14px;
    font-weight: 500;
    z-index: 2147483647;
    box-shadow: 0 8px 24px rgba(0,0,0,0.5);
    animation: slideUp 0.3s ease;
    pointer-events: ${actionLabel ? 'auto' : 'none'};
    max-width: 90%;
    min-width: 300px;
  `;

  document.body.appendChild(toast);

  if (autoClose) {
    setTimeout(() => {
      toast.style.animation = "slideDown 0.3s ease";
      setTimeout(() => toast.remove(), 300);
    }, duration);
  }
  
  return toast;
}

/**
 * Affiche un message d'erreur contextuel avec des suggestions d'action
 * @param {string} errorCode - Code d'erreur pour identifier le type
 * @param {string} message - Message principal
 * @param {Object} context - Contexte supplémentaire (field, value, etc.)
 */
function showContextualError(errorCode, message, context = {}) {
  const errorMessages = {
    'EMAIL_NOT_VERIFIED': {
      message: '📧 Email non vérifié',
      details: 'Veuillez vérifier votre email avant de créer le compte.',
      action: {
        label: 'Vérifier maintenant',
        callback: () => {
          if (typeof showRegisterStep2_5 === 'function') {
            showRegisterStep2_5();
          }
        }
      }
    },
    'EMAIL_ALREADY_EXISTS': {
      message: '\u26A0️ Email déjà utilisé',
      details: `L'email "${context.email || ''}" est déjà associé à un compte.`,
      action: {
        label: 'Se connecter',
        callback: () => {
          if (typeof window.openAuthModal === 'function') {
            window.openAuthModal('login');
          }
        }
      }
    },
    'USERNAME_ALREADY_EXISTS': {
      message: '\u26A0️ Nom d\'utilisateur indisponible',
      details: `Le nom "${context.username || ''}" est déjà pris. Choisissez-en un autre.`,
      action: {
        label: 'Modifier',
        callback: () => {
          if (typeof showRegisterStep2 === 'function') {
            showRegisterStep2();
            // Focus sur le champ username
            setTimeout(() => {
              const usernameInput = document.getElementById('register-username');
              if (usernameInput) {
                usernameInput.focus();
                usernameInput.select();
              }
            }, 100);
          }
        }
      }
    },
    'PASSWORD_TOO_WEAK': {
      message: '🔒 Mot de passe trop faible',
      details: context.details || 'Votre mot de passe ne respecte pas les critères de sécurité.',
      action: {
        label: 'Voir les critères',
        callback: () => {
          // Scroll vers l'indicateur de force du mot de passe
          const passwordInput = document.getElementById('register-password');
          if (passwordInput) {
            passwordInput.focus();
            passwordInput.scrollIntoView({ behavior: 'smooth', block: 'center' });
          }
        }
      }
    },
    'RATE_LIMITED': {
      message: '\u23F1️ Trop de tentatives',
      details: `Veuillez patienter ${context.retryAfter || 0} secondes avant de réessayer.`,
      action: null // Pas d'action pour rate limiting
    },
    'NETWORK_ERROR': {
      message: '🌐 Erreur de connexion',
      details: 'Impossible de se connecter au serveur. Vérifiez votre connexion internet.',
      action: {
        label: 'Réessayer',
        callback: context.retryCallback || (() => window.location.reload())
      }
    },
    'VALIDATION_ERROR': {
      message: '\u270F️ Informations manquantes',
      details: context.details || 'Veuillez compléter tous les champs requis.',
      action: {
        label: 'Voir le champ',
        callback: () => {
          if (context.fieldId) {
            const field = document.getElementById(context.fieldId);
            if (field) {
              field.focus();
              field.scrollIntoView({ behavior: 'smooth', block: 'center' });
              // Ajouter une classe pour highlight
              field.style.borderColor = '#ef4444';
              field.style.boxShadow = '0 0 0 3px rgba(239, 68, 68, 0.1)';
              setTimeout(() => {
                field.style.borderColor = '';
                field.style.boxShadow = '';
              }, 3000);
            }
          }
        }
      }
    }
  };

  const errorConfig = errorMessages[errorCode] || {
    message: '\u274C Erreur',
    details: message,
    action: null
  };

  const fullMessage = `${errorConfig.message}\n${errorConfig.details}`;
  
  showNotification(fullMessage, 'error', {
    duration: errorCode === 'RATE_LIMITED' ? 5000 : 4000,
    actionLabel: errorConfig.action?.label || null,
    onAction: errorConfig.action?.callback || null,
    autoClose: true
  });
}

