window.handlePhotoUpload = function(event) {
  const file = event.target.files[0];
  if (!file) return;
  
  if (!file.type.startsWith('image/')) {
    showNotification("\u26A0️ Veuillez sélectionner une image", "warning");
    return;
  }
  
  const reader = new FileReader();
  reader.onload = function(e) {
    const photoUrl = e.target.result;
    if (!currentUser.photos) currentUser.photos = [];
    currentUser.photos.unshift({ url: photoUrl, timestamp: Date.now() });
    
    // Ajouter à l'historique
    if (!currentUser.history) currentUser.history = [];
    currentUser.history.unshift({
      action: "Photo ajoutée",
      icon: "📸",
      timestamp: Date.now()
    });
    
    saveUser();
    showNotification("\u2705 Photo ajoutée avec succès !", "success");
    openAccountModal(); // Rafraîchir le modal compte
  };
  reader.readAsDataURL(file);
};

